#include <stdio.h>
#include <string.h>
#define MAX 101
char stackArr[MAX];
int top;
void push(char c){ if(top < MAX-1) stackArr[++top] = c; }
char pop(){ if(top >= 0) return stackArr[top--]; return '\0'; }
int main(){
    int T; if(scanf("%d", &T)!=1) return 0; getchar(); // consume newline after T
    char line[MAX];
    for(int tc=0; tc<T; ++tc){
        if(!fgets(line, MAX, stdin)) break;
        line[strcspn(line, "\n")] = '\0'; // remove trailing newline
        top = -1;
        for(int i=0; line[i]; ++i) push(line[i]);
        while(top >= 0) putchar(pop());
        if(tc < T-1) putchar('\n');
    }
    return 0;
}

