#include <bits/stdc++.h>
using namespace std;
const int MAX = 101;
char stackArr[MAX];
int top;
void push(char c){ if(top < MAX-1) stackArr[++top] = c; }
char pop(){ if(top >= 0) return stackArr[top--]; return '\0'; }
int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int T; if(!(cin>>T)) return 0; string dummy; getline(cin, dummy); // consume endline
    for(int tc=0; tc<T; ++tc){
        string s; getline(cin, s);
        top = -1;
        for(char c: s) push(c);
        while(top >= 0) cout << pop();
        if(tc < T-1) cout << '\n';
    }
    return 0;
}

code.Java:
import java.io.*;
public class Main {
    public static void main(String[] args) throws Exception {
        BufferedReader br = new BufferedReader(new InputStreamReader(System.in));
        int T = Integer.parseInt(br.readLine().trim());
        StringBuilder out = new StringBuilder();
        for (int tc = 0; tc < T; ++tc) {
            String s = br.readLine();
            char[] stack = new char[101];
            int top = -1;
            for (int i = 0; i < s.length(); ++i) {
                stack[++top] = s.charAt(i);
            }
            while (top >= 0) out.append(stack[top--]);
            if (tc < T - 1) out.append('\n');
        }
        System.out.print(out.toString());
    }
}

