const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').split('\n');
const T = parseInt(data[0], 10);
let results = [];
for (let i = 1; i <= T; ++i) {
  const str = data[i] ?? '';
  const stack = [];
  for (const ch of str) stack.push(ch);
  let rev = '';
  while (stack.length) rev += stack.pop();
  results.push(rev);
}
console.log(results.join('\n'));
